solutions.python:
class Solution:
    def solve(self):
        query = "SELECT DISTINCT product_name, category FROM (
            SELECT product_name, category, ROW_NUMBER() OVER (PARTITION BY category ORDER BY product_name DESC) as row_num
            FROM products
        ) as subquery
        WHERE row_num = 1
        ORDER BY category DESC, product_name DESC"

